#!/bin/bash
# Generated By: Claude Code (Claude Opus 4.6)
#
# Create and manage OpenShell sandboxes with Claude Code.
# Captures env vars, uploads credentials and ~/.claude/ config,
# clones repos on host, uploads to sandbox, and starts Claude in auto mode.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"
SANDBOXES_DIR="${HOME}/sandboxes"

# Defaults
SANDBOX_NAME=""
CONNECT_NAME=""
DELETE_NAME=""
LIST_MODE=false
NO_CLONE=false
DOWNLOAD_MODE=false
UPLOAD_MODE=false
ADD_REPO_MODE=false
ENSURE_MODE=false
GATEWAY=""
POLICY_FILE=""
SOURCE_DIR=""
REPOS=()
REFS=()
EXTRA_ARGS=()

# ---------------------------------------------------------------------------
# Env var groups — add new groups as needed
# ---------------------------------------------------------------------------

ANTHROPIC_VARS=(
    ANTHROPIC_API_KEY
)

VERTEX_VARS=(
    CLAUDE_CODE_USE_VERTEX
    CLOUD_ML_REGION
    ANTHROPIC_VERTEX_PROJECT_ID
    GOOGLE_APPLICATION_CREDENTIALS
    GOOGLE_CLOUD_PROJECT
    CLOUDSDK_CONFIG
)

JIRA_VARS=(
    JIRA_USERNAME
    JIRA_API_TOKEN
    JIRA_TOKEN
    JIRA_URL
    JIRA_CLOUD_ID
)

GITHUB_VARS=(
    GITHUB_TOKEN
    GH_TOKEN
    GITHUB_USER
)

CLAUDE_VARS=(
    CLAUDE_CODE_MAX_TURNS
    CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC
    CLAUDE_CODE_USE_BEDROCK
)

OTEL_VARS=(
    CLAUDE_CODE_ENABLE_TELEMETRY
    CLAUDE_CODE_ENHANCED_TELEMETRY_BETA
    OTEL_METRICS_EXPORTER
    OTEL_METRIC_EXPORT_INTERVAL
    OTEL_LOGS_EXPORTER
    OTEL_LOGS_EXPORT_INTERVAL
    OTEL_TRACES_EXPORTER
    OTEL_EXPORTER_OTLP_PROTOCOL
    OTEL_EXPORTER_OTLP_ENDPOINT
    OTEL_LOG_TOOL_DETAILS
    OTEL_LOG_USER_PROMPTS
    OTEL_RESOURCE_ATTRIBUTES
)

ALL_VARS=(
    "${ANTHROPIC_VARS[@]}"
    "${VERTEX_VARS[@]}"
    "${JIRA_VARS[@]}"
    "${GITHUB_VARS[@]}"
    "${CLAUDE_VARS[@]}"
    "${OTEL_VARS[@]}"
)

# ---------------------------------------------------------------------------
# Infer sandbox name from CWD if under ~/sandboxes/<name>/
# ---------------------------------------------------------------------------

infer_sandbox_name() {
    local cwd
    cwd="$(pwd)"
    if [[ "$cwd" == "${SANDBOXES_DIR}/"* ]]; then
        local relative="${cwd#${SANDBOXES_DIR}/}"
        echo "${relative%%/*}"
        return 0
    fi
    return 1
}

# ---------------------------------------------------------------------------
# Usage
# ---------------------------------------------------------------------------

usage() {
    cat >&2 <<EOF
Usage: $(basename "$0") [OPTIONS] [-- CLAUDE_ARGS...]

Create an OpenShell sandbox running Claude Code in auto mode.

OPTIONS:
    --create NAME     Create sandbox with this name
    --ensure [NAME]   Create sandbox if missing, reconnect if exists (use with --repo/--ref)
    --repo URL        Git repo to clone on host and upload (repeatable)
    --ref REF         Ref for preceding --repo: branch, pr/<num>, tag/<name>, or SHA
    --source-dir DIR  Copy remotes from local repo and fetch (sandbox has no git auth)
    --add-repo [NAME] Add repo(s) to existing sandbox (use --repo for URL)
    --download [NAME] Download repos from sandbox to ~/sandboxes/<name>/
    --upload [NAME]   Upload local repo changes back into sandbox
    --policy FILE     Override policy file (default: auto-detect home/work)
    --gateway NAME    OpenShell gateway (default: \$OPENSHELL_GATEWAY)
    --connect [NAME]  Reconnect to an existing sandbox
    --delete [NAME]   Delete a sandbox and local state

    NAME is optional for commands marked [NAME] when CWD is under ~/sandboxes/<name>/.
    --no-clone        Skip repo cloning (create sandbox with env + config only)
    --list            List sandboxes
    --help            Show this help

EXAMPLES:
    $(basename "$0") --create nexus --repo git@github.com:org/nexus.git --ref pr/42
    $(basename "$0") --ensure nexus-pr-42 --repo git@github.com:org/nexus.git --ref pr/42
    $(basename "$0") --add-repo nexus --repo git@github.com:org/lib.git --ref v2.0
    $(basename "$0") --download nexus
    $(basename "$0") --upload nexus --repo nexus
    $(basename "$0") --connect nexus
    $(basename "$0") --delete nexus
EOF
    exit "${1:-0}"
}

# ---------------------------------------------------------------------------
# Helper functions
# ---------------------------------------------------------------------------

clone_repo_host() {
    local url="$1" ref="$2" sandbox_dir="$3" source_dir="${4:-}"
    local repo_name
    repo_name=$(basename "$url" .git)
    local target="${sandbox_dir}/${repo_name}"

    if [[ -d "$target" ]]; then
        echo "  ${repo_name} already cloned, skipping" >&2
        return 0
    fi

    # Strip trailing slash — gh CLI fails to resolve repo name with it
    local clean_url="${url%/}"
    git clone "$clean_url" "$target"

    # Copy remotes from source repo and fetch (sandbox has no git auth)
    if [[ -n "$source_dir" && -d "$source_dir/.git" ]]; then
        local remote remote_url
        while IFS= read -r remote; do
            [[ "$remote" == "origin" ]] && continue
            remote_url="$(git -C "$source_dir" remote get-url "$remote")"
            git -C "$target" remote add "$remote" "$remote_url" 2>/dev/null || true
            echo "  fetching remote ${remote}..." >&2
            git -C "$target" fetch "$remote"
        done < <(git -C "$source_dir" remote)
    fi

    if [[ -n "$ref" ]]; then
        if [[ "$ref" =~ ^pr/([0-9]+)$ ]]; then
            local pr_num="${BASH_REMATCH[1]}"
            git -C "$target" fetch origin "pull/${pr_num}/head:pr-${pr_num}"
            git -C "$target" checkout "pr-${pr_num}"
        elif [[ "$ref" =~ ^tag/ ]]; then
            git -C "$target" checkout "tags/${ref#tag/}"
        else
            if ! git -C "$target" checkout "$ref" 2>/dev/null; then
                echo "  warning: ref '${ref}' not found, using default branch" >&2
            fi
        fi
    fi
}

upload_repo() {
    local sandbox_name="$1" sandbox_dir="$2" repo_name="$3"
    openshell sandbox upload "$sandbox_name" "${GW_FLAG[@]}" \
        --no-git-ignore \
        "${sandbox_dir}/${repo_name}" /sandbox/source/
}

write_manifest() {
    local sandbox_dir="$1" sandbox_name="$2" repo_name="$3"
    local url="$4" ref="$5" sha="$6"
    local manifest="${sandbox_dir}/manifest.json"
    local now
    now=$(date -u +"%Y-%m-%dT%H:%M:%SZ")

    if [[ ! -f "$manifest" ]]; then
        jq -n \
            --arg name "$sandbox_name" \
            --arg created "$now" \
            '{name: $name, created: $created, repos: {}}' \
            > "${manifest}.tmp"
        mv "${manifest}.tmp" "$manifest"
    fi

    jq \
        --arg repo "$repo_name" \
        --arg url "$url" \
        --arg ref "$ref" \
        --arg sha "$sha" \
        --arg ts "$now" \
        '.repos[$repo] = {url: $url, ref: $ref, sha: $sha, cloned_at: $ts}' \
        "$manifest" > "${manifest}.tmp"
    mv "${manifest}.tmp" "$manifest"
}

download_sandbox() {
    local sandbox_name="$1" sandbox_dir="$2"
    local manifest="${sandbox_dir}/manifest.json"

    if [[ ! -f "$manifest" ]]; then
        echo "error: no manifest at ${manifest}" >&2
        exit 1
    fi

    local repos
    repos=$(jq -r '.repos | keys[]' "$manifest")

    for repo_name in $repos; do
        echo "  downloading ${repo_name}..." >&2
        mkdir -p "${sandbox_dir}/${repo_name}"
        openshell sandbox download "$sandbox_name" "${GW_FLAG[@]}" \
            "/sandbox/source/${repo_name}" "${sandbox_dir}/${repo_name}"
    done
}

upload_sandbox() {
    local sandbox_name="$1" sandbox_dir="$2" target_repo="${3:-}"
    local manifest="${sandbox_dir}/manifest.json"

    if [[ ! -f "$manifest" ]]; then
        echo "error: no manifest at ${manifest}" >&2
        exit 1
    fi

    if [[ -n "$target_repo" ]]; then
        if [[ ! -d "${sandbox_dir}/${target_repo}" ]]; then
            echo "error: repo not found at ${sandbox_dir}/${target_repo}" >&2
            exit 1
        fi
        echo "  uploading ${target_repo}..." >&2
        upload_repo "$sandbox_name" "$sandbox_dir" "$target_repo"
    else
        local repos
        repos=$(jq -r '.repos | keys[]' "$manifest")
        for repo_name in $repos; do
            if [[ -d "${sandbox_dir}/${repo_name}" ]]; then
                echo "  uploading ${repo_name}..." >&2
                upload_repo "$sandbox_name" "$sandbox_dir" "$repo_name"
            fi
        done
    fi
}

# ---------------------------------------------------------------------------
# Parse args
# ---------------------------------------------------------------------------

while [[ $# -gt 0 ]]; do
    case "$1" in
        --help|-h)
            usage 0
            ;;
        --create)
            [[ $# -ge 2 ]] || { echo "error: --create requires NAME" >&2; exit 1; }
            SANDBOX_NAME="$2"
            shift 2
            ;;
        --policy)
            [[ $# -ge 2 ]] || { echo "error: --policy requires FILE" >&2; exit 1; }
            POLICY_FILE="$2"
            shift 2
            ;;
        --source-dir)
            [[ $# -ge 2 ]] || { echo "error: --source-dir requires PATH" >&2; exit 1; }
            SOURCE_DIR="$2"
            shift 2
            ;;
        --repo)
            [[ $# -ge 2 ]] || { echo "error: --repo requires URL" >&2; exit 1; }
            REPOS+=("$2")
            REFS+=("")
            shift 2
            ;;
        --ref)
            [[ $# -ge 2 ]] || { echo "error: --ref requires REF" >&2; exit 1; }
            if [[ ${#REFS[@]} -gt 0 ]]; then
                REFS[${#REFS[@]}-1]="$2"
            else
                echo "error: --ref must follow --repo or --add-repo" >&2
                exit 1
            fi
            shift 2
            ;;
        --ensure)
            ENSURE_MODE=true
            if [[ $# -ge 2 && "$2" != --* ]]; then
                SANDBOX_NAME="$2"; shift 2
            else
                SANDBOX_NAME="$(infer_sandbox_name)" || { echo "error: --ensure requires NAME (not in a sandbox directory)" >&2; exit 1; }
                shift
            fi
            ;;
        --add-repo)
            ADD_REPO_MODE=true
            if [[ $# -ge 2 && "$2" != --* ]]; then
                SANDBOX_NAME="$2"; shift 2
            else
                SANDBOX_NAME="$(infer_sandbox_name)" || { echo "error: --add-repo requires NAME (not in a sandbox directory)" >&2; exit 1; }
                shift
            fi
            ;;
        --download)
            DOWNLOAD_MODE=true
            if [[ $# -ge 2 && "$2" != --* ]]; then
                SANDBOX_NAME="$2"; shift 2
            else
                SANDBOX_NAME="$(infer_sandbox_name)" || { echo "error: --download requires NAME (not in a sandbox directory)" >&2; exit 1; }
                shift
            fi
            ;;
        --upload)
            UPLOAD_MODE=true
            if [[ $# -ge 2 && "$2" != --* ]]; then
                SANDBOX_NAME="$2"; shift 2
            else
                SANDBOX_NAME="$(infer_sandbox_name)" || { echo "error: --upload requires NAME (not in a sandbox directory)" >&2; exit 1; }
                shift
            fi
            ;;
        --connect)
            if [[ $# -ge 2 && "$2" != --* ]]; then
                CONNECT_NAME="$2"; shift 2
            else
                CONNECT_NAME="$(infer_sandbox_name)" || { echo "error: --connect requires NAME (not in a sandbox directory)" >&2; exit 1; }
                shift
            fi
            ;;
        --delete)
            if [[ $# -ge 2 && "$2" != --* ]]; then
                DELETE_NAME="$2"; shift 2
            else
                DELETE_NAME="$(infer_sandbox_name)" || { echo "error: --delete requires NAME (not in a sandbox directory)" >&2; exit 1; }
                shift
            fi
            ;;
        --list)
            LIST_MODE=true
            shift
            ;;
        --no-clone)
            NO_CLONE=true
            shift
            ;;
        --gateway|-g)
            [[ $# -ge 2 ]] || { echo "error: --gateway requires NAME" >&2; exit 1; }
            GATEWAY="$2"
            shift 2
            ;;
        *)
            EXTRA_ARGS+=("$1")
            shift
            ;;
    esac
done

# ---------------------------------------------------------------------------
# Subcommands
# ---------------------------------------------------------------------------

GW_FLAG=()
if [[ -n "$GATEWAY" ]]; then
    GW_FLAG=(--gateway "$GATEWAY")
fi

if [[ "$LIST_MODE" == true ]]; then
    exec openshell sandbox list "${GW_FLAG[@]}"
    exit $?
elif [[ -n "$DELETE_NAME" ]]; then
    openshell sandbox delete "$DELETE_NAME" "${GW_FLAG[@]}" || true
    if [[ -d "${SANDBOXES_DIR}/${DELETE_NAME}" ]]; then
        rm -rf "${SANDBOXES_DIR}/${DELETE_NAME}"
        echo "removed local state: ${SANDBOXES_DIR}/${DELETE_NAME}" >&2
    fi
    exit 0
elif [[ -n "$CONNECT_NAME" ]]; then
    SANDBOX_DIR="${SANDBOXES_DIR}/${CONNECT_NAME}"
    WORKDIR="/sandbox"
    if [[ -f "${SANDBOX_DIR}/manifest.json" ]]; then
        first_repo=$(jq -r '.repos | keys[0] // empty' "${SANDBOX_DIR}/manifest.json")
        if [[ -n "$first_repo" ]]; then
            WORKDIR="/sandbox/source/${first_repo}"
        fi
    fi
    exec openshell sandbox exec --name "${CONNECT_NAME}" "${GW_FLAG[@]}" \
        --tty --timeout 0 -- bash -c "source /sandbox/.bashrc && cd ${WORKDIR} && /sandbox/bin/claude-wrapper.sh -c || /sandbox/bin/claude-wrapper.sh"
    exit $?
fi

# --- Add repo to existing sandbox ---
if [[ "$ADD_REPO_MODE" == true ]]; then
    if [[ ${#REPOS[@]} -eq 0 ]]; then
        echo "error: --add-repo requires --repo URL" >&2
        exit 1
    fi
    SANDBOX_DIR="${SANDBOXES_DIR}/${SANDBOX_NAME}"
    mkdir -p "$SANDBOX_DIR"

    for i in "${!REPOS[@]}"; do
        repo="${REPOS[$i]}"
        ref="${REFS[$i]:-}"
        repo_name=$(basename "$repo" .git)

        echo "adding ${repo_name} to sandbox ${SANDBOX_NAME}..." >&2
        clone_repo_host "$repo" "$ref" "$SANDBOX_DIR"

        sha=$(git -C "${SANDBOX_DIR}/${repo_name}" rev-parse HEAD)
        write_manifest "$SANDBOX_DIR" "$SANDBOX_NAME" "$repo_name" "$repo" "$ref" "$sha"

        echo "uploading ${repo_name}..." >&2
        upload_repo "$SANDBOX_NAME" "$SANDBOX_DIR" "$repo_name"
    done

    echo "done." >&2
    exit 0
fi

# --- Download from sandbox ---
if [[ "$DOWNLOAD_MODE" == true ]]; then
    SANDBOX_DIR="${SANDBOXES_DIR}/${SANDBOX_NAME}"

    echo "downloading from sandbox ${SANDBOX_NAME}..." >&2
    download_sandbox "$SANDBOX_NAME" "$SANDBOX_DIR"
    echo "done. files in ${SANDBOX_DIR}/" >&2
    exit 0
fi

# --- Upload to sandbox ---
if [[ "$UPLOAD_MODE" == true ]]; then
    SANDBOX_DIR="${SANDBOXES_DIR}/${SANDBOX_NAME}"
    target_repo=""
    if [[ ${#REPOS[@]} -gt 0 ]]; then
        target_repo=$(basename "${REPOS[0]}" .git)
    fi

    echo "uploading to sandbox ${SANDBOX_NAME}..." >&2
    upload_sandbox "$SANDBOX_NAME" "$SANDBOX_DIR" "$target_repo"
    echo "done." >&2
    exit 0
fi

# --- Ensure (create-or-connect) ---
if [[ "$ENSURE_MODE" == true ]]; then
    if openshell sandbox list "${GW_FLAG[@]}" 2>/dev/null | grep -q "^${SANDBOX_NAME}[[:space:]]"; then
        SANDBOX_DIR="${SANDBOXES_DIR}/${SANDBOX_NAME}"
        WORKDIR="/sandbox"
        if [[ -f "${SANDBOX_DIR}/manifest.json" ]]; then
            first_repo=$(jq -r '.repos | keys[0] // empty' "${SANDBOX_DIR}/manifest.json")
            if [[ -n "$first_repo" ]]; then
                WORKDIR="/sandbox/source/${first_repo}"
            fi
        fi
        echo "sandbox '${SANDBOX_NAME}' exists, connecting..." >&2
        exec openshell sandbox exec --name "${SANDBOX_NAME}" "${GW_FLAG[@]}" \
            --tty --timeout 0 -- bash -c "source /sandbox/.bashrc && cd ${WORKDIR} && /sandbox/bin/claude-wrapper.sh -c || /sandbox/bin/claude-wrapper.sh"
    else
        ENSURE_ARGS=(--create "$SANDBOX_NAME")
        for i in "${!REPOS[@]}"; do
            ENSURE_ARGS+=(--repo "${REPOS[$i]}")
            if [[ -n "${REFS[$i]:-}" ]]; then
                ENSURE_ARGS+=(--ref "${REFS[$i]}")
            fi
        done
        [[ -n "$GATEWAY" ]] && ENSURE_ARGS+=(--gateway "$GATEWAY")
        [[ -n "$POLICY_FILE" ]] && ENSURE_ARGS+=(--policy "$POLICY_FILE")
        [[ -n "$SOURCE_DIR" ]] && ENSURE_ARGS+=(--source-dir "$SOURCE_DIR")
        exec "$0" "${ENSURE_ARGS[@]}"
    fi
fi

# ---------------------------------------------------------------------------
# Validate --create required when --repo specified
# ---------------------------------------------------------------------------

if [[ -z "$SANDBOX_NAME" && "$NO_CLONE" != true && ${#REPOS[@]} -gt 0 ]]; then
    echo "error: --create required when --repo is specified" >&2
    exit 1
fi

# ---------------------------------------------------------------------------
# Resolve policy
# ---------------------------------------------------------------------------

if [[ -z "$POLICY_FILE" ]]; then
    profile="home"
    if [[ -n "${CLAUDE_CODE_USE_VERTEX+x}" ]]; then
        profile="work"
    fi

    POLICY_FILE="${REPO_ROOT}/policies/${profile}.yaml"
    if [[ ! -f "$POLICY_FILE" ]]; then
        echo "error: policy file not found: ${POLICY_FILE}" >&2
        exit 1
    fi
fi

# ---------------------------------------------------------------------------
# Generate /sandbox/.env content (runtime env vars)
# ---------------------------------------------------------------------------

# Populate GH_TOKEN from secret-tool if not already set
if [[ -z "${GH_TOKEN:-}" ]] && command -v secret-tool >/dev/null 2>&1; then
    GH_TOKEN=$(secret-tool lookup github openshell-sandbox-ro 2>/dev/null || true)
    if [[ -n "$GH_TOKEN" ]]; then
        export GH_TOKEN
    fi
fi

ENV_CONTENT=""
captured=0
for var in "${ALL_VARS[@]}"; do
    if [[ -n "${!var+x}" ]]; then
        ENV_CONTENT+="$(printf '%s=%q' "$var" "${!var}")"$'\n'
        captured=$((captured + 1))
    fi
done

# Remap credential file paths for sandbox
if [[ -n "${GOOGLE_APPLICATION_CREDENTIALS+x}" ]]; then
    ENV_CONTENT+=$'\n'"GOOGLE_APPLICATION_CREDENTIALS=/sandbox/.config/gcloud/application_default_credentials.json"
fi

if [[ $captured -eq 0 ]]; then
    echo "warning: no env vars captured, sandbox will have no credentials" >&2
else
    echo "captured $captured env vars" >&2
fi

# ---------------------------------------------------------------------------
# Create sandbox
# ---------------------------------------------------------------------------

CREATE_CMD=(openshell sandbox create "${GW_FLAG[@]}" --no-auto-providers --keep)

if [[ -n "$SANDBOX_NAME" ]]; then
    CREATE_CMD+=(--name "$SANDBOX_NAME")
fi

CREATE_CMD+=(--policy "$POLICY_FILE")

SANDBOX_TARGET="${SANDBOX_NAME:-}"

echo "creating sandbox..." >&2
echo "  policy:  ${POLICY_FILE}" >&2
echo "" >&2

# sandbox create hangs on SSH connect (podman driver issue).
# Run in background, poll for sandbox, then use sandbox exec.
"${CREATE_CMD[@]}" &>/dev/null &
CREATE_PID=$!

elapsed=0
while ! openshell sandbox list "${GW_FLAG[@]}" 2>/dev/null | grep -q "${SANDBOX_TARGET}"; do
    sleep 1
    elapsed=$((elapsed + 1))
    if [[ $elapsed -ge 60 ]]; then
        kill "$CREATE_PID" 2>/dev/null || true
        echo "error: sandbox did not appear within 60s" >&2
        exit 1
    fi
done

sleep 2
kill "$CREATE_PID" 2>/dev/null || true
wait "$CREATE_PID" 2>/dev/null || true

# Create host-side state directory
if [[ -n "$SANDBOX_TARGET" ]]; then
    mkdir -p "${SANDBOXES_DIR}/${SANDBOX_TARGET}"
fi

# ---------------------------------------------------------------------------
# Upload credentials
# ---------------------------------------------------------------------------

echo "uploading credentials..." >&2

if [[ -d "${HOME}/.config/gcloud" ]]; then
    openshell sandbox upload "${SANDBOX_TARGET}" "${GW_FLAG[@]}" \
        "${HOME}/.config/gcloud" /sandbox/.config
fi

# ---------------------------------------------------------------------------
# Upload ~/.claude/ (resolve symlinks, strip for sandbox)
# ---------------------------------------------------------------------------

echo "uploading claude config..." >&2
if [[ -d "${HOME}/.claude" ]]; then
    CLAUDE_TMP="$(mktemp -d)"
    rsync -rL \
        --exclude=projects \
        --exclude=agentpulse \
        --exclude=venvs \
        --exclude=file-history \
        --exclude=backups \
        --exclude=paste-cache \
        --exclude=debug \
        --exclude=my-claude-stuff-data \
        --exclude=claude-dashboard \
        --exclude=.git \
        "${HOME}/.claude/" "${CLAUDE_TMP}/.claude/"

    # Strip settings.json: remove allow permissions and hooks, rewrite paths
    # (sandbox policy is the security boundary)
    if [[ -f "${CLAUDE_TMP}/.claude/settings.json" ]]; then
        python3 -c "
import json, sys
with open(sys.argv[1], 'r') as f:
    raw = f.read()
raw = raw.replace(sys.argv[2], '/sandbox')
s = json.loads(raw)
for key in list(s.keys()):
    if key.startswith('permissions') and 'allow' in key.lower():
        del s[key]
s.pop('hooks', None)
with open(sys.argv[1], 'w') as f:
    json.dump(s, f, indent=2)
" "${CLAUDE_TMP}/.claude/settings.json" "${HOME}"
    fi

    # Rewrite host HOME paths to /sandbox in all plugin config files
    if [[ -d "${CLAUDE_TMP}/.claude/plugins" ]]; then
        find "${CLAUDE_TMP}/.claude/plugins" -name "*.json" -exec \
            sed -i "s|${HOME}|/sandbox|g" {} +
    fi

    # Stage .bashrc and .env into temp dir
    cp "${REPO_ROOT}/config/bashrc" "${CLAUDE_TMP}/.bashrc"
    echo "$ENV_CONTENT" > "${CLAUDE_TMP}/.env"

    # Upload config to /sandbox (uploads accumulate, not clobber)
    openshell sandbox upload "${SANDBOX_TARGET}" "${GW_FLAG[@]}" \
        "${CLAUDE_TMP}/.claude" /sandbox
    openshell sandbox upload "${SANDBOX_TARGET}" "${GW_FLAG[@]}" \
        "${CLAUDE_TMP}/.bashrc" /sandbox
    openshell sandbox upload "${SANDBOX_TARGET}" "${GW_FLAG[@]}" \
        "${CLAUDE_TMP}/.env" /sandbox
    rm -rf "$CLAUDE_TMP"
fi

# Re-upload bin/ (OpenShell may reset home dir during sandbox create)
openshell sandbox upload "${SANDBOX_TARGET}" "${GW_FLAG[@]}" \
    "${REPO_ROOT}/bin" /sandbox

# ---------------------------------------------------------------------------
# Clone repos on host and upload to sandbox
# ---------------------------------------------------------------------------

if [[ "$NO_CLONE" != true && ${#REPOS[@]} -eq 0 ]]; then
    current_remote=$(git remote get-url origin 2>/dev/null || true)
    if [[ -n "$current_remote" ]]; then
        REPOS+=("$current_remote")
        REFS+=("")
    fi
fi

WORKDIR="/sandbox"
if [[ "$NO_CLONE" != true && ${#REPOS[@]} -gt 0 ]]; then
    SANDBOX_DIR="${SANDBOXES_DIR}/${SANDBOX_TARGET}"
    mkdir -p "$SANDBOX_DIR"

    echo "cloning repos on host..." >&2
    for i in "${!REPOS[@]}"; do
        repo="${REPOS[$i]}"
        ref="${REFS[$i]:-}"
        repo_name=$(basename "$repo" .git)

        echo "  ${repo_name}${ref:+ (${ref})}" >&2
        clone_repo_host "$repo" "$ref" "$SANDBOX_DIR" "$SOURCE_DIR"

        sha=$(git -C "${SANDBOX_DIR}/${repo_name}" rev-parse HEAD)
        write_manifest "$SANDBOX_DIR" "$SANDBOX_TARGET" "$repo_name" "$repo" "$ref" "$sha"

        echo "  uploading ${repo_name} to sandbox..." >&2
        upload_repo "$SANDBOX_TARGET" "$SANDBOX_DIR" "$repo_name"
    done

    first_repo=$(basename "${REPOS[0]}" .git)
    WORKDIR="/sandbox/source/$first_repo"
fi

# ---------------------------------------------------------------------------
# Start Claude Code
# ---------------------------------------------------------------------------

echo "starting claude in ${WORKDIR}..." >&2
exec openshell sandbox exec --name "${SANDBOX_TARGET}" "${GW_FLAG[@]}" \
    --tty --timeout 0 -- bash -c "source /sandbox/.bashrc && cd $WORKDIR && /sandbox/bin/claude-wrapper.sh -c || /sandbox/bin/claude-wrapper.sh"
exit $?
